    fread(&one, sizeof(struct Student), 1, fp);
    printf("2번째 학생: %s (%d, %.1f)\n", one.name, one.age, one.gpa);
    rewind(fp);
    fread(&one, sizeof(struct Student), 1, fp);
    printf("1번째 학생: %s (%d, %.1f)\n", one.name, one.age, one.gpa);
    fclose(fp);
    return 0;
